const AWS = require('aws-sdk');
const s3 = new AWS.S3();

exports.handler = async (event) => {
    const bucketName = event.Records[0].s3.bucket.name;
    const key = decodeURIComponent(event.Records[0].s3.object.key.replace(/\+/g, ' '));
    
    try {
        // Read the file from S3
        const params = { Bucket: bucketName, Key: key };
        const data = await s3.getObject(params).promise();
        
        // Process the file (example: convert to uppercase)
        const processedData = data.Body.toString().toUpperCase();
        
        // Save results to another S3 location
        const outputBucket = 'your-output-bucket';
        const outputKey = key.replace(/\.\w+$/, '.processed.txt');
        await s3.putObject({ Bucket: outputBucket, Key: outputKey, Body: processedData }).promise();
        
        return {
            statusCode: 200,
            body: JSON.stringify('File processed and saved successfully'),
        };
    } catch (error) {
        console.error(error);
        return {
            statusCode: 500,
            body: JSON.stringify('Error processing file'),
        };
    }
};